{"version":"NotebookV1","origId":1083584440949942,"name":"10-6 Decision Trees","language":"scala","commands":[{"version":"CommandV1","origId":1083584440949943,"guid":"f974a6ff-561e-4297-ab1e-fc4f8934b4f0","subtype":"command","commandType":"auto","position":1.0,"command":"\n%md\n# Decision Trees\n\nIn the previous notebook, you were working with the parametric model, Linear Regression. We could do some more hyperparameter tuning with the linear regression model, but we're going to try tree based methods and see if our performance improves.","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"f5775a21-306c-43d2-87a2-841f1d6a995c"},{"version":"CommandV1","origId":1083584440949944,"guid":"9103a446-e899-4ec8-a0f0-258949a953f3","subtype":"command","commandType":"auto","position":2.0,"command":"val filePath = \"/databricks-datasets/learning-spark-v2/sf-airbnb/sf-airbnb-clean.parquet\"\nval airbnbDF = spark.read.parquet(filePath)\nval Array(trainDF, testDF) = airbnbDF.randomSplit(Array(.8, .2), seed=42)","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"ta