mmandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"22c04624-e63b-43da-9f27-74cecd4d6050"},{"version":"CommandV1","origId":1083584440949946,"guid":"aece6ef4-69aa-4f18-a8f0-fff9e46f6952","subtype":"command","commandType":"auto","position":4.0,"command":"import org.apache.spark.ml.feature.StringIndexer\n\nval categoricalCols = trainDF.dtypes.filter(_._2 == \"StringType\").map(_._1)\nval indexOutputCols = categoricalCols.map(_ + \"Index\")\n\nval stringIndexer = new StringIndexer()\n  .setInputCols(categoricalCols)\n  .setOutputCols(indexOutputCols)\n  .setHandleInvalid(\"skip\")","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"df3f9053-9c1d-4407-9c01-1787dfee99cb"},{"version":"CommandV1","origId":1083584440949947,"guid":"1ac6b592-7c70-48db-ab9b-49ec916158d2","subtype":"command","commandType":"auto","position":5.0,"command":"%md\n## VectorAssembler\n\nLet's use the VectorAssembler to combine all of our categorical and numeric inputs [Python](https://spark.apache.org/docs/latest/api/python/pyspark.ml.html#pyspark.ml.feature.VectorAssembler)/[Scala](https://spark.apache.org/docs/latest/api/scala/#org.apache.spark.ml.feature.VectorAssembler).","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"e1f270ec-f18c-4c71-9cff-5365f87e4d90"},{"version":"CommandV1","origId":1083584440949948,"guid":"12be3cb4-e57c-48fb-ab9b-13834464f08f","subtype":"command","commandType":"auto","position":6.0,"command":"import org.apache.spark.ml.feature.VectorAssembler\n\n// Filter for just numeric columns (and exclude price, our label)\nval numericCols = trainDF.dtypes.filter{ case (field, dataType) => \n  dataType == \"DoubleType\" && field != \"price\"}.map(_._1)\n// Combine output of StringIndexer defined above and numeric columns\nval assemblerInputs = indexOutputCols ++ numericCols\nval vecAssembler = new VectorAssembler()\n  .setInputCols(assemblerInputs)\n  .setOutputCol(\"features\")","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffIn